import type { ActorEntry, IGenericViewport, IStackViewport, IViewport, IVolumeViewport, ViewportContentMode, VOIRange } from '../types';
export type ImageSliceViewport = IViewport & Pick<IStackViewport, 'getCurrentImageId' | 'getCurrentImageIdIndex' | 'getImageIds' | 'hasImageURI'>;
